function AbsoluteDifference(a: int, b: int): int
{
  if a > b then a - b else b - a
}

predicate threeSumClosestPost(nums: seq<int>, target: int, result: int)
{
  |nums| >= 3
  &&
  (exists i,j,k :: 0 <= i < j < k < |nums| &&
                 nums[i] + nums[j] + nums[k] == result)
  &&
  (forall i,j,k :: 0 <= i < j < k < |nums| ==>
       AbsoluteDifference(nums[i] + nums[j] + nums[k], target)
         >= AbsoluteDifference(result, target))
}

// If two sequences have the same multiset, any triple sum achievable in one
// is achievable in the other.
lemma MultisetTripleSumEquiv(a: seq<int>, b: seq<int>, val: int)
  requires multiset(a) == multiset(b)
  requires exists i,j,k :: 0 <= i < j < k < |a| && a[i] + a[j] + a[k] == val
  ensures  exists i,j,k :: 0 <= i < j < k < |b| && b[i] + b[j] + b[k] == val
{
  var i, j, k :| 0 <= i < j < k < |a| && a[i] + a[j] + a[k] == val;
  var x, y, z := a[i], a[j], a[k];
  // x, y, z are all in multiset(a) = multiset(b)
  // We need to find distinct indices in b with these values
  assert x in multiset(a);
  assert y in multiset(a);
  assert z in multiset(a);

  // Build a multiset of {x, y, z} and show it's a submultiset of multiset(b)
  var triple := multiset{x, y, z};

  // Since i < j < k, these are distinct indices in a
  // So triple is a submultiset of multiset(a) = multiset(b)
  assert triple <= multiset(a) by {
    // a[i], a[j], a[k] are at distinct indices
    var s := a[..];
    assert s == a;
    MultisetSubmultisetFromDistinctIndices(a, i, j, k);
  }

  assert triple <= multiset(b);

  // Now extract indices from b
  ExtractTripleIndices(b, x, y, z, val);
}

lemma MultisetSubmultisetFromDistinctIndices(s: seq<int>, i: int, j: int, k: int)
  requires 0 <= i < j < k < |s|
  ensures multiset{s[i], s[j], s[k]} <= multiset(s)
{
  // Proof by showing we can decompose s around these indices
  var m := multiset(s);
  var t := multiset{s[i], s[j], s[k]};

  // Each element at a distinct index contributes to the multiset
  assert s[i] in m;
  assert s[j] in m;
  assert s[k] in m;

  // We need to show the multiplicities work out
  // Split s into pieces around the indices
  assert s == s[..i] + [s[i]] + s[i+1..j] + [s[j]] + s[j+1..k] + [s[k]] + s[k+1..];
  assert m == multiset(s[..i]) + multiset{s[i]} + multiset(s[i+1..j]) + multiset{s[j]} + multiset(s[j+1..k]) + multiset{s[k]} + multiset(s[k+1..]);
  assert t <= multiset{s[i]} + multiset{s[j]} + multiset{s[k]};
  assert multiset{s[i]} + multiset{s[j]} + multiset{s[k]} <= m;
}

lemma ExtractTripleIndices(b: seq<int>, x: int, y: int, z: int, val: int)
  requires multiset{x, y, z} <= multiset(b)
  requires x + y + z == val
  ensures exists i,j,k :: 0 <= i < j < k < |b| && b[i] + b[j] + b[k] == val
{
  // Find first occurrence of x
  var i := FindInSeq(b, x);
  assert b[i] == x;

  // Remove x from consideration: the remaining multiset still contains y, z
  var b' := b[..i] + b[i+1..];
  assert multiset(b') == multiset(b) - multiset{x};
  assert multiset{y, z} <= multiset(b');

  // Find y in b'
  var j' := FindInSeq(b', y);
  assert b'[j'] == y;

  // Remove y: remaining still contains z
  var b'' := b'[..j'] + b'[j'+1..];
  assert multiset(b'') == multiset(b') - multiset{y};
  assert multiset{z} <= multiset(b'');

  var k' := FindInSeq(b'', z);
  assert b''[k'] == z;

  // Map j' back to index in b
  var j := if j' < i then j' else j' + 1;
  assert b[j] == y by {
    if j' < i {
      assert b'[j'] == b[j'];
    } else {
      assert b'[j'] == b[j' + 1];
    }
  }
  assert i != j;

  // Map k' back to index in b' then to b
  var k_in_bprime := if k' < j' then k' else k' + 1;
  assert b'[k_in_bprime] == z by {
    if k' < j' {
      assert b''[k'] == b'[k'];
    } else {
      assert b''[k'] == b'[k' + 1];
    }
  }
  var k := if k_in_bprime < i then k_in_bprime else k_in_bprime + 1;
  assert b[k] == z by {
    if k_in_bprime < i {
      assert b'[k_in_bprime] == b[k_in_bprime];
    } else {
      assert b'[k_in_bprime] == b[k_in_bprime + 1];
    }
  }
  assert i != k;
  assert j != k;

  // Now sort {i, j, k} to get i' < j' < k'
  SortThreeDistinct(b, i, j, k, x, y, z, val);
}

lemma FindInSeq(s: seq<int>, x: int) returns (idx: int)
  requires x in multiset(s)
  ensures 0 <= idx < |s|
  ensures s[idx] == x
{
  if s[0] == x {
    idx := 0;
  } else {
    assert multiset(s) == multiset{s[0]} + multiset(s[1..]);
    assert x in multiset(s[1..]);
    var idx' := FindInSeq(s[1..], x);
    idx := idx' + 1;
  }
}

lemma SortThreeDistinct(b: seq<int>, i: int, j: int, k: int, x: int, y: int, z: int, val: int)
  requires 0 <= i < |b| && 0 <= j < |b| && 0 <= k < |b|
  requires i != j && i != k && j != k
  requires b[i] == x && b[j] == y && b[k] == z
  requires x + y + z == val
  ensures exists i',j',k' :: 0 <= i' < j' < k' < |b| && b[i'] + b[j'] + b[k'] == val
{
  // Sort the three indices
  var a, bb, c: int;
  if i < j && i < k {
    a := i;
    if j < k { bb := j; c := k; }
    else { bb := k; c := j; }
  } else if j < i && j < k {
    a := j;
    if i < k { bb := i; c := k; }
    else { bb := k; c := i; }
  } else {
    a := k;
    if i < j { bb := i; c := j; }
    else { bb := j; c := i; }
  }
  assert 0 <= a < bb < c < |b|;
  assert b[a] + b[bb] + b[c] == val;
}

// Lemma: for any triple in b, the same sum is achievable in a (reverse direction)
lemma MultisetTripleSumEquivReverse(a: seq<int>, b: seq<int>, i: int, j: int, k: int)
  requires multiset(a) == multiset(b)
  requires 0 <= i < j < k < |b|
  ensures exists i',j',k' :: 0 <= i' < j' < k' < |a| && a[i'] + a[j'] + a[k'] == b[i] + b[j] + b[k]
{
  var val := b[i] + b[j] + b[k];
  assert exists ii,jj,kk :: 0 <= ii < jj < kk < |b| && b[ii] + b[jj] + b[kk] == val;
  MultisetTripleSumEquiv(b, a, val);
}

predicate Sorted(a: array<int>, lo: int, hi: int)
  reads a
  requires 0 <= lo <= hi <= a.Length
{
  forall p, q :: lo <= p < q < hi ==> a[p] <= a[q]
}

// Predicate: v is achievable as a triple sum from arr[0..n]
predicate IsTripleSumOf(v: int, s: seq<int>)
{
  exists i, j, k :: 0 <= i < j < k < |s| && s[i] + s[j] + s[k] == v
}

method threeSumClosest(nums: seq<int>, target: int) returns (result: int)
  requires |nums| >= 3
  ensures  threeSumClosestPost(nums, target, result)
{
    var n := |nums|;
    if n < 3 { return 0; }

    var arr := new int[n];
    var i := 0;
    while i < n
      invariant 0 <= i <= n
      invariant forall p :: 0 <= p < i ==> arr[p] == nums[p]
    {
        arr[i] := nums[i];
        i := i + 1;
    }

    assert arr[..] == nums;

    ghost var origArr := arr[..];
    assert origArr == nums;

    // Selection sort
    i := 0;
    while i < n
      invariant 0 <= i <= n
      invariant arr.Length == n
      invariant multiset(arr[..]) == multiset(nums)
      // Everything before i is sorted
      invariant Sorted(arr, 0, i)
      // Everything before i is <= everything from i onward
      invariant forall p, q :: 0 <= p < i <= q < n ==> arr[p] <= arr[q]
    {
        var j := i + 1;
        // Inner loop: find minimum in arr[i..n] by bubbling it to position i
        // Actually this is more like selection sort via swapping
        while j < n
          invariant i + 1 <= j <= n
          invariant arr.Length == n
          invariant multiset(arr[..]) == multiset(nums)
          invariant Sorted(arr, 0, i)
          invariant forall p, q :: 0 <= p < i <= q < n ==> arr[p] <= arr[q]
          // arr[i] is <= everything in arr[i+1..j]
          invariant forall q :: i < q < j ==> arr[i] <= arr[q]
        {
            if arr[j] < arr[i] {
                var temp := arr[i];
                arr[i] := arr[j];
                arr[j] := temp;
                assert arr[..] == arr[..i] + [arr[i]] + arr[i+1..j] + [arr[j]] + arr[j+1..];
            }
            j := j + 1;
        }
        // After inner loop: arr[i] is the minimum of arr[i..n]
        assert forall q :: i <= q < n ==> arr[i] <= arr[q];
        i := i + 1;
    }

    assert Sorted(arr, 0, n);
    assert multiset(arr[..]) == multiset(nums);

    ghost var sortedSeq := arr[..];

    var closest := arr[0] + arr[1] + arr[2];

    assert IsTripleSumOf(closest, arr[..]) by {
      assert 0 < 1 < 2 < |arr[..]|;
      assert arr[..][0] + arr[..][1] + arr[..][2] == closest;
    }

    i := 0;
    while i < n - 2
      invariant 0 <= i <= n - 2
      invariant arr.Length == n
      invariant arr[..] == sortedSeq
      invariant multiset(arr[..]) == multiset(nums)
      invariant Sorted(arr, 0, n)
      invariant IsTripleSumOf(closest, arr[..])
      // closest is at least as close as any triple sum involving indices < i
      invariant forall a, b, c :: 0 <= a < i && a < b < c < n ==>
        AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
    {
        var left := i + 1;
        var right := n - 1;

        while left < right
          invariant i + 1 <= left
          invariant right < n
          invariant left <= right + 1
          invariant arr.Length == n
          invariant arr[..] == sortedSeq
          invariant multiset(arr[..]) == multiset(nums)
          invariant Sorted(arr, 0, n)
          invariant IsTripleSumOf(closest, arr[..])
          // all triples (i, b, c) with b < left or c > right have been considered
          invariant forall a, b, c :: 0 <= a < i && a < b < c < n ==>
            AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
          invariant forall b, c :: i < b < c < n && (b < left || c > right) ==>
            AbsoluteDifference(arr[i] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
        {
            var curSum := arr[i] + arr[left] + arr[right];

            if curSum == target {
                // curSum == target, so AbsoluteDifference is 0, can't do better
                assert IsTripleSumOf(curSum, arr[..]) by {
                  assert arr[..][i] + arr[..][left] + arr[..][right] == curSum;
                }

                // Need to establish postcondition
                closest := curSum;

                // Prove postcondition: closest is a triple sum of nums
                assert IsTripleSumOf(closest, arr[..]);
                MultisetTripleSumEquiv(arr[..], nums, closest);
                assert exists ii,jj,kk :: 0 <= ii < jj < kk < |nums| && nums[ii] + nums[jj] + nums[kk] == closest;

                // And it's optimal (distance 0)
                assert AbsoluteDifference(closest, target) == 0;
                assert forall ii,jj,kk :: 0 <= ii < jj < kk < |nums| ==>
                  AbsoluteDifference(nums[ii] + nums[jj] + nums[kk], target) >= 0;

                return curSum;
            }

            var diffCur := if target > curSum then target - curSum else curSum - target;
            var diffClosest := if target > closest then target - closest else closest - target;

            if diffCur < diffClosest {
                closest := curSum;
            }

            assert IsTripleSumOf(closest, arr[..]);

            if curSum < target {
                // We move left pointer right. Need to show all triples (i, left, c)
                // with c > right are already covered (they are by inner invariant)
                // and (i, left, c) for c <= right: since arr is sorted and
                // curSum < target, moving right would only decrease the sum further
                assert forall c :: left < c <= right ==>
                  arr[i] + arr[left] + arr[c] <= arr[i] + arr[left] + arr[right] by {
                    assert forall c :: left < c <= right ==> arr[c] <= arr[right];
                  }
                assert forall c :: left < c <= right ==>
                  arr[i] + arr[left] + arr[c] <= curSum;
                // Since curSum < target, all these sums are also < target
                // So their distance = target - sum >= target - curSum = diffCur >= diffClosest (after update)
                assert forall c :: left < c <= right ==>
                  AbsoluteDifference(arr[i] + arr[left] + arr[c], target) >= target - curSum;
                assert target - curSum >= AbsoluteDifference(closest, target);

                left := left + 1;
            } else {
                // curSum > target (we handled == above)
                // Move right pointer left. For triples (i, b, right) with b >= left:
                // since arr sorted, moving left up increases the sum
                assert curSum > target;
                assert forall b :: left <= b < right ==>
                  arr[i] + arr[b] + arr[right] >= arr[i] + arr[left] + arr[right] by {
                    assert forall b :: left <= b < right ==> arr[b] >= arr[left];
                  }
                assert forall b :: left <= b < right ==>
                  arr[i] + arr[b] + arr[right] >= curSum;
                assert forall b :: left <= b < right ==>
                  AbsoluteDifference(arr[i] + arr[b] + arr[right], target) >= curSum - target;
                assert curSum - target >= AbsoluteDifference(closest, target);

                right := right - 1;
            }
        }
        i := i + 1;
    }

    // At end: closest is optimal over ALL triples
    // The outer loop invariant gives us: all triples (a,b,c) with a < n-2 covered
    // Since we need a < b < c and c < n, we need a < n-2
    assert forall a, b, c :: 0 <= a < n - 2 && a < b < c < n ==>
      AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target);
    // Any valid triple has a <= n-3 = n-2-1 < n-2, so all triples are covered
    assert forall a, b, c :: 0 <= a < b < c < n ==>
      AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target);

    // Transfer from arr to nums
    assert IsTripleSumOf(closest, arr[..]);
    MultisetTripleSumEquiv(arr[..], nums, closest);

    // Optimality: any triple in nums corresponds to a triple in arr
    forall ii, jj, kk | 0 <= ii < jj < kk < |nums|
      ensures AbsoluteDifference(nums[ii] + nums[jj] + nums[kk], target) >= AbsoluteDifference(closest, target)
    {
      MultisetTripleSumEquivReverse(arr[..], nums, ii, jj, kk);
      var a, b, c :| 0 <= a < b < c < |arr[..]| && arr[..][a] + arr[..][b] + arr[..][c] == nums[ii] + nums[jj] + nums[kk];
      assert arr[a] + arr[b] + arr[c] == nums[ii] + nums[jj] + nums[kk];
      assert AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target);
    }

    result := closest;
}

