                assert forall b :: left <= b < right ==> sortedSeq[b] >= sortedSeq[left];
              }
            assert forall b :: left <= b < right ==>
              sortedSeq[outerI] + sortedSeq[b] + sortedSeq[right] >= curSum;
            assert curSum - target >= AbsoluteDifference(closest, target);

            right := right - 1;
        }
    }
