265→        AbsoluteDifference(sortedSeq[a] + sortedSeq[b] + sortedSeq[c], target) >= AbsoluteDifference(closest, target)
266→    {
267→        closest := InnerTwoPointer(arr, n, target, closest, i, sortedSeq);
268→        i := i + 1;
269→    }
270→
271→    // Transfer to nums
272→    TransferToNums(sortedSeq, nums, closest, target, n);
273→}
274→
275→// Helper lemma for the left-move case in two-pointer
276→lemma LeftMoveLemma(sortedSeq: seq<int>, outerI: int, left: int, right: int, n: int,
277→                    curSum: int, target: int, closest: int)
278→  requires |sortedSeq| == n
279→  requires SeqSorted(sortedSeq)
280→  requires 0 <= outerI < left < right < n
281→  requires curSum == sortedSeq[outerI] + sortedSeq[left] + sortedSeq[right]
282→  requires curSum < target
283→  requires AbsoluteDifference(closest, target) <= AbsoluteDifference(curSum, target)
284→  ensures forall c :: left < c <= right ==>
285→    AbsoluteDifference(sortedSeq[outerI] + sortedSeq[left] + sortedSeq[c], target) >= AbsoluteDifference(closest, target)
286→{
287→  forall c | left < c <= right
288→    ensures AbsoluteDifference(sortedSeq[outerI] + sortedSeq[left] + sortedSeq[c], target) >= AbsoluteDifference(closest, target)
289→  {
290→    assert sortedSeq[c] <= sortedSeq[right];
291→    var s := sortedSeq[outerI] + sortedSeq[left] + sortedSeq[c];
292→    assert s <= curSum;
293→    assert s <= curSum < target;
294→    assert AbsoluteDifference(s, target) == target - s;
295→    assert AbsoluteDifference(curSum, target) == target - curSum;
296→    assert target - s >= target - curSum;
297→  }
298→}
299→
300→// Helper lemma for the right-move case in two-pointer
301→lemma RightMoveLemma(sortedSeq: seq<int>, outerI: int, left: int, right: int, n: int,
302→                     curSum: int, target: int, closest: int)
303→  requires |sortedSeq| == n
304→  requires SeqSorted(sortedSeq)
305→  requires 0 <= outerI < left < right < n
306→  requires curSum == sortedSeq[outerI] + sortedSeq[left] + sortedSeq[right]
307→  requires curSum > target
308→  requires AbsoluteDifference(closest, target) <= AbsoluteDifference(curSum, target)
309→  ensures forall b :: left <= b < right ==>
310→    AbsoluteDifference(sortedSeq[outerI] + sortedSeq[b] + sortedSeq[right], target) >= AbsoluteDifference(closest, target)
311→{
312→  forall b | left <= b < right
313→    ensures AbsoluteDifference(sortedSeq[outerI] + sortedSeq[b] + sortedSeq[right], target) >= AbsoluteDifference(closest, target)
314→  {
315→    assert sortedSeq[b] >= sortedSeq[left];
316→    var s := sortedSeq[outerI] + sortedSeq[b] + sortedSeq[right];
317→    assert s >= curSum;
318→    assert s >= curSum > target;
319→    assert AbsoluteDifference(s, target) == s - target;
320→    assert AbsoluteDifference(curSum, target) == curSum - target;
321→    assert s - target >= curSum - target;
322→  }
323→}
