325→method InnerTwoPointer(arr: array<int>, n: int, target: int, initClosest: int,
326→                       outerI: int, ghost sortedSeq: seq<int>)
327→  returns (closest: int)
328→  requires arr.Length == n
329→  requires n >= 3
330→  requires 0 <= outerI < n - 2
331→  requires arr[..] == sortedSeq
332→  requires SeqSorted(sortedSeq)
333→  requires IsTripleSumOf(initClosest, sortedSeq)
334→  requires forall a, b, c :: 0 <= a < outerI && a < b < c < n ==>
335→    AbsoluteDifference(sortedSeq[a] + sortedSeq[b] + sortedSeq[c], target) >= AbsoluteDifference(initClosest, target)
336→  ensures arr[..] == sortedSeq
337→  ensures IsTripleSumOf(closest, sortedSeq)
338→  ensures forall a, b, c :: 0 <= a <= outerI && a < b < c < n ==>
339→    AbsoluteDifference(sortedSeq[a] + sortedSeq[b] + sortedSeq[c], target) >= AbsoluteDifference(closest, target)
340→{
341→    closest := initClosest;
342→    var left := outerI + 1;
343→    var right := n - 1;
344→
345→    while left < right
346→      invariant outerI + 1 <= left
347→      invariant right < n
348→      invariant left <= right + 1
349→      invariant arr.Length == n
350→      invariant arr[..] == sortedSeq
351→      invariant IsTripleSumOf(closest, sortedSeq)
352→      invariant forall a, b, c :: 0 <= a < outerI && a < b < c < n ==>
353→        AbsoluteDifference(sortedSeq[a] + sortedSeq[b] + sortedSeq[c], target) >= AbsoluteDifference(closest, target)
354→      invariant forall b, c :: outerI < b < c < n && (b < left || c > right) ==>
355→        AbsoluteDifference(sortedSeq[outerI] + sortedSeq[b] + sortedSeq[c], target) >= AbsoluteDifference(closest, target)
356→    {
357→        var curSum := arr[outerI] + arr[left] + arr[right];
358→        assert curSum == sortedSeq[outerI] + sortedSeq[left] + sortedSeq[right];
359→
360→        if curSum == target {
361→            closest := curSum;
362→            assert IsTripleSumOf(closest, sortedSeq);
363→            assert AbsoluteDifference(closest, target) == 0;
364→            return;
365→        }
366→
367→        ghost var oldClosest := closest;
368→        var diffCur := AbsoluteDifference(curSum, target);
369→        var diffClosest := AbsoluteDifference(closest, target);
370→
371→        if diffCur < diffClosest {
372→            closest := curSum;
373→            assert IsTripleSumOf(closest, sortedSeq);
374→        }
375→
376→        // After potential update, closest is at least as good as curSum
377→        assert AbsoluteDifference(closest, target) <= AbsoluteDifference(curSum, target);
378→
379→        if curSum < target {
380→            LeftMoveLemma(sortedSeq, outerI, left, right, n, curSum, target, closest);
381→            left := left + 1;
382→        } else {
383→            assert curSum > target;
384→            RightMoveLemma(sortedSeq, outerI, left, right, n, curSum, target, closest);
385→            right := right - 1;
386→        }
387→    }
388→}
