390→lemma TransferToNums(sortedSeq: seq<int>, nums: seq<int>, closest: int, target: int, n: int)
391→  requires |sortedSeq| == n
392→  requires |nums| == n
393→  requires n >= 3
394→  requires multiset(sortedSeq) == multiset(nums)
395→  requires IsTripleSumOf(closest, sortedSeq)
396→  requires forall a, b, c :: 0 <= a < b < c < n ==>
397→    AbsoluteDifference(sortedSeq[a] + sortedSeq[b] + sortedSeq[c], target) >= AbsoluteDifference(closest, target)
398→  ensures threeSumClosestPost(nums, target, closest)
399→{
400→  // closest is a triple sum of sortedSeq, transfer to nums
401→  MultisetTripleSumEquiv(sortedSeq, nums, closest);
402→
403→  // Optimality: for any triple in nums, there's one in sortedSeq with same sum
404→  forall ii, jj, kk | 0 <= ii < jj < kk < |nums|
405→    ensures AbsoluteDifference(nums[ii] + nums[jj] + nums[kk], target) >= AbsoluteDifference(closest, target)
406→  {
407→    MultisetTripleSumEquivReverse(sortedSeq, nums, ii, jj, kk);
408→    var a, b, c :| 0 <= a < b < c < |sortedSeq| && sortedSeq[a] + sortedSeq[b] + sortedSeq[c] == nums[ii] + nums[jj] + nums[kk];
409→  }
410→}
411→
